{
  "name": "RoadSidePro: AI Automotive & Cycle Repair",
  "description": "An all-in-one mobile roadside assistance platform for automotive and bicycle repairs featuring AI-driven diagnostics, local service discovery with Google Maps, up-to-date repair data with Google Search, and advanced vehicle visualization using Veo and Gemini 3.",
  "requestFramePermissions": [
    "camera",
    "geolocation"
  ]
}

export interface RepairMessage {
  role: 'user' | 'model';
  text: string;
  urls?: Array<{ title: string; uri: string }>;
  timestamp: number;
}

export enum AppMode {
  ASSIST = 'assist',
  VISUALIZE = 'visualize',
  SEARCH = 'search',
  MAPS = 'maps'
}

export interface ImageGenConfig {
  size: '1K' | '2K' | '4K';
  aspectRatio: '1:1' | '3:4' | '4:3' | '9:16' | '16:9';
}

export interface VideoGenConfig {
  aspectRatio: '16:9' | '9:16';
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { RepairMessage, ImageGenConfig, VideoGenConfig } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const searchGroundingAssistant = async (prompt: string): Promise<GenerateContentResponse> => {
  const ai = getAIClient();
  return await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      systemInstruction: "You are an expert automotive and bicycle mechanic assistant. Provide accurate troubleshooting steps for vehicle and bike problems. If the query is about specific parts or news, use Google Search to provide up-to-date information. Always cite your sources.",
    },
  });
};

export const mapsGroundingAssistant = async (prompt: string, location?: { latitude: number, longitude: number }): Promise<GenerateContentResponse> => {
  const ai = getAIClient();
  const config: any = {
    tools: [{ googleMaps: {} }],
  };

  if (location) {
    config.toolConfig = {
      retrievalConfig: {
        latLng: location
      }
    };
  }

  return await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: prompt,
    config,
  });
};

export const generateVehicleImage = async (prompt: string, config: ImageGenConfig): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [{ text: prompt }],
    },
    config: {
      imageConfig: {
        aspectRatio: config.aspectRatio,
        imageSize: config.size
      }
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image data generated");
};

export const generateVehicleVideo = async (
  prompt: string, 
  base64Image: string, 
  config: VideoGenConfig,
  onProgress: (msg: string) => void
): Promise<string> => {
  const ai = getAIClient();
  onProgress("Initializing video generation operation...");

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    image: {
      imageBytes: base64Image.split(',')[1],
      mimeType: 'image/png',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: config.aspectRatio
    }
  });

  onProgress("Rendering your cinematic vehicle sequence. This usually takes a few minutes...");

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
    onProgress("Still working on it... refining the motion and lighting.");
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video generation failed");

  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

import React from 'react';

interface KeySelectionGateProps {
  onKeySelected: () => void;
  title: string;
  description: string;
}

export const KeySelectionGate: React.FC<KeySelectionGateProps> = ({ onKeySelected, title, description }) => {
  const handleSelectKey = async () => {
    try {
      // @ts-ignore
      await window.aistudio.openSelectKey();
      onKeySelected();
    } catch (e) {
      console.error("Failed to open key selector", e);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center p-8 bg-white rounded-2xl shadow-xl border border-slate-200 max-w-md mx-auto my-12 text-center">
      <div className="w-16 h-16 bg-amber-100 rounded-full flex items-center justify-center mb-6">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-amber-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" />
        </svg>
      </div>
      <h2 className="text-2xl font-bold mb-4">{title}</h2>
      <p className="text-slate-600 mb-8">{description}</p>
      <div className="bg-blue-50 p-4 rounded-lg mb-8 text-sm text-blue-800">
        <p>This feature requires a selected API key from a paid GCP project. <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="underline font-semibold">View billing docs</a></p>
      </div>
      <button 
        onClick={handleSelectKey}
        className="w-full bg-slate-900 text-white py-3 px-6 rounded-xl font-semibold hover:bg-slate-800 transition-colors shadow-lg shadow-slate-200"
      >
        Select API Key to Unlock
      </button>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { RepairMessage, AppMode } from '../types';
import { searchGroundingAssistant, mapsGroundingAssistant } from '../services/geminiService';

interface ChatInterfaceProps {
  mode: AppMode;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ mode }) => {
  const [messages, setMessages] = useState<RepairMessage[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, loading]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || loading) return;

    const userMsg: RepairMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      let response;
      if (mode === AppMode.SEARCH) {
        response = await searchGroundingAssistant(input);
      } else {
        // Attempt to get geolocation for Maps grounding
        let loc;
        try {
          const position = await new Promise<GeolocationPosition>((res, rej) => 
            navigator.geolocation.getCurrentPosition(res, rej)
          );
          loc = { latitude: position.coords.latitude, longitude: position.coords.longitude };
        } catch (err) {
          console.warn("Location permission denied", err);
        }
        response = await mapsGroundingAssistant(input, loc);
      }

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      const urls: Array<{ title: string; uri: string }> = [];

      if (groundingChunks) {
        groundingChunks.forEach((chunk: any) => {
          if (chunk.web) urls.push({ title: chunk.web.title, uri: chunk.web.uri });
          if (chunk.maps) urls.push({ title: chunk.maps.title, uri: chunk.maps.uri });
        });
      }

      const modelMsg: RepairMessage = {
        role: 'model',
        text: response.text || "I'm sorry, I couldn't generate a response.",
        urls: urls.length > 0 ? urls : undefined,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Error: Could not connect to the repair database. Please check your connection.", timestamp: Date.now() }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] max-w-4xl mx-auto w-full">
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center space-y-4 px-8">
            <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center">
              {mode === AppMode.SEARCH ? (
                <svg className="w-8 h-8 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
              ) : (
                <svg className="w-8 h-8 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
              )}
            </div>
            <h3 className="text-xl font-semibold">
              {mode === AppMode.SEARCH ? "Search Grounded Assistant" : "Maps Grounded Assistant"}
            </h3>
            <p className="text-slate-500 max-w-xs">
              {mode === AppMode.SEARCH 
                ? "Ask about specific car parts, bicycle gear, or the latest automotive repair standards." 
                : "Find nearby repair shops, tire centers, or check local mobile mechanics."}
            </p>
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm ${m.role === 'user' ? 'bg-slate-900 text-white' : 'bg-white border border-slate-200 text-slate-800'}`}>
              <p className="whitespace-pre-wrap text-sm leading-relaxed">{m.text}</p>
              {m.urls && m.urls.length > 0 && (
                <div className="mt-3 pt-3 border-t border-slate-100 space-y-2">
                  <p className="text-xs font-bold uppercase tracking-wider text-slate-400">Sources & Links</p>
                  {m.urls.map((url, idx) => (
                    <a key={idx} href={url.uri} target="_blank" className="block text-xs text-blue-500 hover:underline truncate">
                      🔗 {url.title || url.uri}
                    </a>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-200 rounded-2xl p-4 flex space-x-2 items-center shadow-sm">
              <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
              <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-.3s]"></div>
              <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-.5s]"></div>
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSend} className="p-4 border-t bg-white">
        <div className="relative flex items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={mode === AppMode.SEARCH ? "Search for repair info..." : "Locate a repair service..."}
            className="w-full pl-4 pr-12 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:outline-none focus:ring-2 focus:ring-slate-900 focus:border-transparent transition-all"
          />
          <button
            type="submit"
            disabled={loading || !input.trim()}
            className="absolute right-2 p-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 disabled:bg-slate-300 disabled:cursor-not-allowed transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { generateVehicleImage, generateVehicleVideo } from '../services/geminiService';
import { ImageGenConfig, VideoGenConfig } from '../types';

export const Visualizer: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [imageConfig, setImageConfig] = useState<ImageGenConfig>({ size: '1K', aspectRatio: '16:9' });
  const [videoConfig, setVideoConfig] = useState<VideoGenConfig>({ aspectRatio: '16:9' });
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [generatedVideo, setGeneratedVideo] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState('');
  const [view, setView] = useState<'image' | 'video'>('image');

  const handleGenerateImage = async () => {
    if (!prompt.trim() || loading) return;
    setLoading(true);
    setLoadingMsg("Designing your custom vehicle concept...");
    try {
      const img = await generateVehicleImage(prompt, imageConfig);
      setGeneratedImage(img);
      setGeneratedVideo(null); // Clear video when new image generated
    } catch (e) {
      console.error(e);
      alert("Failed to generate image. Please ensure your API key is correctly selected and active.");
    } finally {
      setLoading(false);
      setLoadingMsg('');
    }
  };

  const handleAnimateImage = async () => {
    if (!generatedImage || loading) return;
    setLoading(true);
    try {
      const video = await generateVehicleVideo(
        `Cinematic drive of the vehicle in the image, professional lighting, smooth motion.`,
        generatedImage,
        videoConfig,
        (msg) => setLoadingMsg(msg)
      );
      setGeneratedVideo(video);
      setView('video');
    } catch (e) {
      console.error(e);
      alert("Failed to animate image. Please retry or check your project quota.");
    } finally {
      setLoading(false);
      setLoadingMsg('');
    }
  };

  return (
    <div className="max-w-4xl mx-auto w-full p-4 space-y-8">
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-200">
        <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
          <svg className="w-6 h-6 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"/></svg>
          Vehicle Concept Visualizer
        </h3>

        <div className="space-y-4">
          <textarea
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            placeholder="Describe your dream repair outcome or custom vehicle build..."
            className="w-full p-4 rounded-xl bg-slate-50 border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 h-24 resize-none"
          />

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Image Size</label>
              <div className="flex gap-2">
                {(['1K', '2K', '4K'] as const).map(size => (
                  <button
                    key={size}
                    onClick={() => setImageConfig({ ...imageConfig, size })}
                    className={`flex-1 py-2 px-3 rounded-lg text-sm font-medium border transition-all ${imageConfig.size === size ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-300'}`}
                  >
                    {size}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Aspect Ratio</label>
              <select
                value={imageConfig.aspectRatio}
                onChange={(e) => {
                  const val = e.target.value as any;
                  setImageConfig({ ...imageConfig, aspectRatio: val });
                  setVideoConfig({ ...videoConfig, aspectRatio: val === '9:16' ? '9:16' : '16:9' });
                }}
                className="w-full p-2 bg-white border border-slate-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-indigo-500"
              >
                <option value="16:9">Landscape (16:9)</option>
                <option value="9:16">Portrait (9:16)</option>
                <option value="1:1">Square (1:1)</option>
                <option value="4:3">Classic (4:3)</option>
              </select>
            </div>
          </div>

          <button
            onClick={handleGenerateImage}
            disabled={loading || !prompt.trim()}
            className="w-full py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 disabled:bg-slate-300 transition-all shadow-lg shadow-indigo-100"
          >
            {loading ? 'Processing...' : 'Generate High-Res Concept'}
          </button>
        </div>
      </div>

      {(generatedImage || loading) && (
        <div className="bg-slate-900 rounded-3xl overflow-hidden shadow-2xl relative min-h-[400px] flex items-center justify-center">
          {loading && (
            <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm z-10 flex flex-col items-center justify-center text-white p-8">
              <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-6"></div>
              <p className="text-lg font-medium text-center max-w-sm">{loadingMsg}</p>
            </div>
          )}

          <div className="w-full h-full flex items-center justify-center p-4">
            {view === 'image' && generatedImage && (
              <img src={generatedImage} alt="Generated vehicle" className="max-w-full max-h-[60vh] object-contain rounded-xl shadow-lg" />
            )}
            {view === 'video' && generatedVideo && (
              <video src={generatedVideo} autoPlay loop muted controls className="max-w-full max-h-[60vh] object-contain rounded-xl shadow-lg" />
            )}
          </div>

          {generatedImage && !loading && (
            <div className="absolute bottom-6 left-6 right-6 flex justify-between gap-4">
               <div className="flex bg-slate-800/80 backdrop-blur rounded-xl p-1 p-2 gap-2">
                <button 
                  onClick={() => setView('image')}
                  className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${view === 'image' ? 'bg-white text-slate-900 shadow' : 'text-slate-300 hover:text-white'}`}
                >
                  Concept
                </button>
                <button 
                  onClick={() => { if(generatedVideo) setView('video') }}
                  disabled={!generatedVideo}
                  className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all disabled:opacity-50 ${view === 'video' ? 'bg-white text-slate-900 shadow' : 'text-slate-300 hover:text-white'}`}
                >
                  Motion
                </button>
               </div>

               {!generatedVideo && (
                 <button 
                  onClick={handleAnimateImage}
                  className="bg-indigo-500 hover:bg-indigo-600 text-white text-sm font-bold px-6 py-2 rounded-xl transition-all flex items-center gap-2 shadow-lg"
                 >
                   <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M2 6a2 2 0 012-2h6a2 2 0 012 2v8a2 2 0 01-2 2H4a2 2 0 01-2-2V6zM14.553 7.106A1 1 0 0014 8v4a1 1 0 00.553.894l2 1A1 1 0 0018 13V7a1 1 0 00-1.447-.894l-2 1z"></path></svg>
                   Animate with Veo
                 </button>
               )}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppMode } from './types';
import { ChatInterface } from './components/ChatInterface';
import { Visualizer } from './components/Visualizer';
import { KeySelectionGate } from './components/KeySelectionGate';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppMode>(AppMode.ASSIST);
  const [hasKey, setHasKey] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      // @ts-ignore
      if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
        // @ts-ignore
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasKey(selected);
      }
    };
    checkKey();
  }, []);

  const renderContent = () => {
    switch (activeTab) {
      case AppMode.ASSIST:
      case AppMode.SEARCH:
        return <ChatInterface mode={AppMode.SEARCH} />;
      case AppMode.MAPS:
        return <ChatInterface mode={AppMode.MAPS} />;
      case AppMode.VISUALIZE:
        if (!hasKey) {
          return (
            <KeySelectionGate 
              title="Unlock High-Performance AI" 
              description="To use cinematic vehicle animation (Veo) and ultra-high-resolution concepts (Gemini 3 Pro), you must select an authorized API key."
              onKeySelected={() => setHasKey(true)}
            />
          );
        }
        return <Visualizer />;
      default:
        return <ChatInterface mode={AppMode.SEARCH} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-slate-900 rounded-lg flex items-center justify-center text-white font-bold italic">R</div>
            <span className="text-xl font-bold tracking-tight text-slate-800 hidden sm:block">RoadSidePro</span>
          </div>

          <div className="bg-amber-50 px-3 py-1 rounded-full border border-amber-200 flex items-center space-x-2">
            <div className="w-2 h-2 bg-amber-500 rounded-full animate-pulse"></div>
            <span className="text-[10px] font-bold text-amber-800 uppercase tracking-widest">Active Assistant</span>
          </div>
        </div>
      </header>

      {/* Main Area */}
      <main className="flex-1 overflow-hidden">
        {renderContent()}
      </main>

      {/* Persistent Call-to-Action / Navigation */}
      <nav className="bg-white border-t border-slate-200 pb-safe fixed bottom-0 left-0 right-0 z-50 shadow-[0_-4px_10px_rgba(0,0,0,0.03)]">
        <div className="max-w-2xl mx-auto flex justify-around p-2">
          <button 
            onClick={() => setActiveTab(AppMode.SEARCH)}
            className={`flex flex-col items-center p-2 rounded-xl transition-all ${activeTab === AppMode.SEARCH ? 'text-slate-900 bg-slate-100' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <svg className="w-6 h-6 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
            <span className="text-[10px] font-bold uppercase tracking-wider">Search</span>
          </button>

          <button 
            onClick={() => setActiveTab(AppMode.MAPS)}
            className={`flex flex-col items-center p-2 rounded-xl transition-all ${activeTab === AppMode.MAPS ? 'text-slate-900 bg-slate-100' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <svg className="w-6 h-6 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
            <span className="text-[10px] font-bold uppercase tracking-wider">Services</span>
          </button>

