export const diagnoseAssistant = async (prompt: string): Promise<GenerateContentResponse> => {
  const ai = getAIClient();
  return await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 4000 },
      systemInstruction: `You are a Master Automotive & Bicycle Diagnostic Technician. 
      Your goal is to analyze symptoms, sounds, smells, or OBD-II error codes provided by the user.
      Provide a structured diagnostic report including:
      1. Potential Primary Cause.
      2. Severity Level (Safe to Drive / Urgent / Immediate Stop).
      3. Estimated Diagnostic Difficulty (1-10).
      4. Step-by-step troubleshooting or temporary roadside fixes.
      Be precise, technical yet accessible, and prioritize safety above all else.`,
    },
  });
};

export const generateVehicleImage = async (prompt: string, config: ImageGenConfig): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [{ text: prompt }],
    },
    config: {
      imageConfig: {
        aspectRatio: config.aspectRatio,
        imageSize: config.size
      }
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image data generated");
};

export const generateVehicleVideo = async (
  prompt: string, 
  base64Image: string, 
  config: VideoGenConfig,
  onProgress: (msg: string) => void
): Promise<string> => {
  const ai = getAIClient();
  onProgress("Initializing video generation operation...");

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    image: {
      imageBytes: base64Image.split(',')[1],
      mimeType: 'image/png',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: config.aspectRatio
    }
  });

  onProgress("Rendering your cinematic vehicle sequence. This usually takes a few minutes...");

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
    onProgress("Still working on it... refining the motion and lighting.");
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video generation failed");

  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

import React, { useState, useRef, useEffect } from 'react';
import { RepairMessage, AppMode } from '../types';
import { searchGroundingAssistant, mapsGroundingAssistant, diagnoseAssistant } from '../services/geminiService';

interface ChatInterfaceProps {
  mode: AppMode;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ mode }) => {
  const [messages, setMessages] = useState<RepairMessage[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, loading]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || loading) return;

    const userMsg: RepairMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      let response;
      if (mode === AppMode.DIAGNOSE) {
        response = await diagnoseAssistant(input);
      } else if (mode === AppMode.SEARCH) {
        response = await searchGroundingAssistant(input);
      } else {
        let loc;
        try {
          const position = await new Promise<GeolocationPosition>((res, rej) => 
            navigator.geolocation.getCurrentPosition(res, rej)
          );
          loc = { latitude: position.coords.latitude, longitude: position.coords.longitude };
        } catch (err) {
          console.warn("Location permission denied", err);
        }
        response = await mapsGroundingAssistant(input, loc);
      }

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      const urls: Array<{ title: string; uri: string }> = [];

      if (groundingChunks) {
        groundingChunks.forEach((chunk: any) => {
          if (chunk.web) urls.push({ title: chunk.web.title, uri: chunk.web.uri });
          if (chunk.maps) urls.push({ title: chunk.maps.title, uri: chunk.maps.uri });
        });
      }

      const modelMsg: RepairMessage = {
        role: 'model',
        text: response.text || "I'm sorry, I couldn't generate a response.",
        urls: urls.length > 0 ? urls : undefined,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Error: Could not connect to the repair database. Please check your connection.", timestamp: Date.now() }]);
    } finally {
      setLoading(false);
    }
  };

  const getPlaceholder = () => {
    if (mode === AppMode.DIAGNOSE) return "Enter symptoms (e.g. 'clunking sound') or error code...";
    if (mode === AppMode.SEARCH) return "Search for repair info...";
    return "Locate a repair service...";
  };

  const getWelcomeIcon = () => {
    if (mode === AppMode.DIAGNOSE) {
      return (
        <svg className="w-8 h-8 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" />
        </svg>
      );
    }
    if (mode === AppMode.SEARCH) {
      return <svg className="w-8 h-8 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>;
    }
    return <svg className="w-8 h-8 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"/></svg>;
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] max-w-4xl mx-auto w-full">
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center space-y-4 px-8">
            <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center">
              {getWelcomeIcon()}
            </div>
            <h3 className="text-xl font-semibold">
              {mode === AppMode.DIAGNOSE ? "AI-Driven Diagnostics" : mode === AppMode.SEARCH ? "Search Grounded Assistant" : "Maps Grounded Assistant"}
            </h3>
            <p className="text-slate-500 max-w-xs">
              {mode === AppMode.DIAGNOSE 
                ? "Input any vehicle symptom or OBD-II error code for a master technician's analysis." 
                : mode === AppMode.SEARCH 
                  ? "Ask about specific car parts, bicycle gear, or the latest automotive repair standards." 
                  : "Find nearby repair shops, tire centers, or check local mobile mechanics."}
            </p>
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm ${m.role === 'user' ? 'bg-slate-900 text-white' : 'bg-white border border-slate-200 text-slate-800'}`}>
              <p className="whitespace-pre-wrap text-sm leading-relaxed">{m.text}</p>
              {m.urls && m.urls.length > 0 && (
                <div className="mt-3 pt-3 border-t border-slate-100 space-y-2">
                  <p className="text-xs font-bold uppercase tracking-wider text-slate-400">Sources & Links</p>
                  {m.urls.map((url, idx) => (
                    <a key={idx} href={url.uri} target="_blank" className="block text-xs text-blue-500 hover:underline truncate">
                      🔗 {url.title || url.uri}
                    </a>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-200 rounded-2xl p-4 flex space-x-2 items-center shadow-sm">
              <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce"></div>
              <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce [animation-delay:-.3s]"></div>
              <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce [animation-delay:-.5s]"></div>
              <span className="text-xs font-medium text-slate-400 ml-2">Analyzing technical data...</span>
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSend} className="p-4 border-t bg-white">
        <div className="relative flex items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={getPlaceholder()}
            className="w-full pl-4 pr-12 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:outline-none focus:ring-2 focus:ring-slate-900 focus:border-transparent transition-all"
          />
          <button
            type="submit"
            disabled={loading || !input.trim()}
            className="absolute right-2 p-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 disabled:bg-slate-300 disabled:cursor-not-allowed transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
          </button>
        </div>
      </form>
    </div>
  );
};

