import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';

export const LiveAssist: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState<'idle' | 'connecting' | 'connected' | 'error'>('idle');
  const [transcript, setTranscript] = useState<string[]>([]);

  const audioContextInRef = useRef<AudioContext | null>(null);
  const audioContextOutRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const encode = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const startCall = async () => {
    setStatus('connecting');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      audioContextInRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextOutRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStatus('connected');
            setIsActive(true);
            const source = audioContextInRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(session => session.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextInRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTranscript(prev => [...prev.slice(-4), `AI: ${text}`]);
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              const ctx = audioContextOutRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onclose: () => endCall(),
          onerror: (e) => {
            console.error("Live error", e);
            setStatus('error');
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          outputAudioTranscription: {},
          systemInstruction: "You are a professional Rapid Response Roadside Technician. A user is stranded and needs immediate verbal guidance. Be calm, clear, and safety-focused. Guide them through checking basics (gas, battery, tires) or simple bicycle fixes. Use short, direct instructions suited for voice conversation.",
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setStatus('error');
    }
  };

  const endCall = () => {
    setIsActive(false);
    setStatus('idle');
    setTranscript([]);
    if (sessionRef.current) {
      // sessionRef.current.close() is implicit in most implementations or managed via closing context
    }
    audioContextInRef.current?.close();
    audioContextOutRef.current?.close();
  };

  return (
    <div className="flex flex-col items-center justify-center h-full p-6 text-center space-y-8 bg-slate-900 text-white overflow-hidden">
      <div className="relative">
        <div className={`w-32 h-32 rounded-full border-4 border-blue-500/30 flex items-center justify-center transition-all duration-500 ${isActive ? 'scale-110 shadow-[0_0_50px_rgba(59,130,246,0.5)]' : ''}`}>
          <div className={`w-24 h-24 rounded-full bg-blue-600 flex items-center justify-center ${isActive ? 'animate-pulse' : ''}`}>
             <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
             </svg>
          </div>
        </div>
        {isActive && (
          <div className="absolute -inset-4 border-2 border-blue-400 rounded-full animate-ping opacity-20"></div>
        )}
      </div>

      <div className="space-y-2">
        <h2 className="text-2xl font-bold tracking-tight">Rapid Response AI Tech</h2>
        <p className="text-slate-400 text-sm max-w-xs mx-auto">
          {status === 'idle' && "Need hands-free guidance? Call our AI Technician now."}
          {status === 'connecting' && "Establishing secure voice link..."}
          {status === 'connected' && "Technician is listening. Ask anything."}
          {status === 'error' && "Connection failed. Please check your mic and try again."}
        </p>
      </div>

      <div className="w-full max-w-sm h-32 bg-slate-800/50 rounded-2xl p-4 overflow-hidden border border-slate-700 flex flex-col justify-end">
        {transcript.length === 0 ? (
          <p className="text-slate-500 text-xs italic">Voice transcription will appear here...</p>
        ) : (
          transcript.map((line, i) => (
            <p key={i} className="text-xs text-blue-300 mb-1 last:font-bold last:text-white animate-in slide-in-from-bottom-2">
              {line}
            </p>
          ))
        )}
      </div>

      <div className="flex gap-4 w-full max-w-xs">
        {!isActive ? (
          <button 
            onClick={startCall}
            disabled={status === 'connecting'}
            className="flex-1 bg-blue-600 hover:bg-blue-700 py-4 rounded-2xl font-bold shadow-lg shadow-blue-900/40 active:scale-95 transition-all disabled:opacity-50"
          >
            {status === 'connecting' ? 'Connecting...' : 'Start Voice Call'}
          </button>
        ) : (
          <button 
            onClick={endCall}
            className="flex-1 bg-red-600 hover:bg-red-700 py-4 rounded-2xl font-bold shadow-lg shadow-red-900/40 active:scale-95 transition-all"
          >
            End Assistance
          </button>
        )}
      </div>

      <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">
        Always stay in a safe location before using hands-free assistance
      </p>
    </div>
  );
};

