import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { RepairMessage, ImageGenConfig, VideoGenConfig } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const searchGroundingAssistant = async (prompt: string): Promise<GenerateContentResponse> => {
  const ai = getAIClient();
  return await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      systemInstruction: "You are an expert automotive and bicycle mechanic assistant. Provide accurate troubleshooting steps for vehicle and bike problems. If the query is about specific parts or news, use Google Search to provide up-to-date information. Always cite your sources.",
    },
  });
};

export const getDailyDeals = async (): Promise<GenerateContentResponse> => {
  const ai = getAIClient();
  const today = new Date().toLocaleDateString();
  return await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Find the 5 best current online deals, discounts, or trending accessories for automotive repair and bicycle maintenance for ${today}. Focus on items like portable tire inflators, jump starters, multi-tools, or high-quality lubricants. Provide names, a brief reason why it's a good deal, and the URL.`,
    config: {
      tools: [{ googleSearch: {} }],
      systemInstruction: "You are a smart shopping assistant for motorists and cyclists. Your goal is to find the best value-for-money repair parts and accessories available today. Always include source URLs from grounding metadata.",
    },
  });
};

export const mapsGroundingAssistant = async (prompt: string, location?: { latitude: number, longitude: number }): Promise<GenerateContentResponse> => {
  const ai = getAIClient();
  const config: any = {
    tools: [{ googleMaps: {} }],
  };

  if (location) {
    config.toolConfig = {
      retrievalConfig: {
        latLng: location
      }
    };
  }

  return await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: prompt,
    config,
  });
};

export const diagnoseAssistant = async (prompt: string, image?: { data: string, mimeType: string }): Promise<GenerateContentResponse> => {
  const ai = getAIClient();
  const parts: any[] = [{ text: prompt }];

  if (image) {
    parts.unshift({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  return await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      thinkingConfig: { thinkingBudget: 4000 },
      systemInstruction: `You are a Master Automotive & Bicycle Diagnostic Technician. 
      Analyze symptoms, sounds, smells, error codes, or visual dashboard indicators.
      If an image is provided, identify warning lights (Check Engine, ABS, etc.) or text from scanner screens.
      Provide a structured diagnostic report including:
      1. Potential Primary Cause.
      2. Severity Level (Safe to Drive / Urgent / Immediate Stop).
      3. Estimated Diagnostic Difficulty (1-10).
      4. Step-by-step troubleshooting or temporary roadside fixes.

      CRITICAL: If the issue is severe (Severity Urgent or Immediate Stop) or the user seems overwhelmed, RECOMMEND that they use the 'Request On-Site Tech' dispatch feature in the app to have a physical repairman come to their location immediately.

      Safety is the number one priority.`,
    },
  });
};

export const generateVehicleImage = async (
  prompt: string, 
  config: ImageGenConfig, 
  referenceImage?: { data: string, mimeType: string }
): Promise<string> => {
  const ai = getAIClient();

  const parts: any[] = [{ text: prompt }];

  if (referenceImage) {
    parts.unshift({
      inlineData: {
        data: referenceImage.data,
        mimeType: referenceImage.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: parts,
    },
    config: {
      imageConfig: {
        aspectRatio: config.aspectRatio,
        imageSize: config.size
      }
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image data generated");
};

export const generateVehicleVideo = async (
  prompt: string, 
  base64Image: string, 
  config: VideoGenConfig,
  onProgress: (msg: string) => void
): Promise<string> => {
  const ai = getAIClient();
  onProgress("Initializing video generation operation...");

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    image: {
      imageBytes: base64Image.split(',')[1],
      mimeType: 'image/png',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: config.aspectRatio
    }
  });

  onProgress("Rendering your cinematic vehicle sequence. This usually takes a few minutes...");

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
    onProgress("Still working on it... refining the motion and lighting.");
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video generation failed");

  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

import React, { useState, useEffect } from 'react';
import { getDailyDeals } from '../services/geminiService';
import { ChatInterface } from './ChatInterface';
import { AppMode } from '../types';

interface Deal {
  title: string;
  description: string;
  url: string;
}

export const PartsShop: React.FC = () => {
  const [deals, setDeals] = useState<Deal[]>([]);
  const [loadingDeals, setLoadingDeals] = useState(true);

  useEffect(() => {
    const fetchDeals = async () => {
      try {
        const response = await getDailyDeals();
        const text = response.text || "";
        const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

        // Simple heuristic to extract items from the grounded response
        // In a production app, we'd use a more robust parser or specific schema.
        const lines = text.split('\n').filter(l => l.trim().length > 10);
        const extractedDeals: Deal[] = [];

        const urls = groundingChunks?.map((c: any) => c.web?.uri).filter(Boolean) || [];

        lines.slice(0, 5).forEach((line, idx) => {
          extractedDeals.push({
            title: line.split(':')[0] || "Featured Part",
            description: line.substring(line.indexOf(':') + 1).trim(),
            url: urls[idx] || urls[0] || "#"
          });
        });

        setDeals(extractedDeals);
      } catch (err) {
        console.error("Failed to fetch daily deals", err);
      } finally {
        setLoadingDeals(false);
      }
    };

    fetchDeals();
  }, []);

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] w-full overflow-hidden bg-slate-50">
      {/* Daily Deals Section */}
      <div className="bg-white border-b border-slate-200 p-4 shrink-0 overflow-x-auto whitespace-nowrap scrollbar-hide">
        <div className="flex items-center gap-2 mb-3">
          <div className="bg-amber-100 text-amber-600 p-1.5 rounded-lg">
            <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M11 3a1 1 0 10-2 0v1a1 1 0 102 0V3zM15.657 5.757a1 1 0 00-1.414-1.414l-.707.707a1 1 0 001.414 1.414l.707-.707zM18 10a1 1 0 01-1 1h-1a1 1 0 110-2h1a1 1 0 011 1zM5.05 6.464A1 1 0 106.464 5.05l-.707-.707a1 1 0 00-1.414 1.414l.707.707zM5 10a1 1 0 01-1 1H3a1 1 0 110-2h1a1 1 0 011 1zM8 16v-1h4v1a2 2 0 11-4 0zM12 14c.015-.34.208-.646.477-.859a4 4 0 10-4.954 0c.27.213.462.519.477.859h4z"></path></svg>
          </div>
          <h3 className="text-xs font-black uppercase tracking-widest text-slate-800">AI Daily Deal Finder</h3>
          <span className="text-[10px] font-bold text-amber-500 animate-pulse bg-amber-50 px-2 py-0.5 rounded-full ml-auto">UPDATED DAILY</span>
        </div>

        <div className="flex gap-4 min-w-max pb-2">
          {loadingDeals ? (
            Array(3).fill(0).map((_, i) => (
              <div key={i} className="w-64 h-24 bg-slate-100 rounded-2xl animate-pulse"></div>
            ))
          ) : (
            deals.map((deal, i) => (
              <a 
                key={i} 
                href={deal.url} 
                target="_blank" 
                className="w-72 bg-white border border-slate-200 rounded-2xl p-4 shadow-sm hover:shadow-md transition-all group flex flex-col justify-between"
              >
                <div>
                  <h4 className="text-sm font-bold text-slate-900 group-hover:text-blue-600 truncate mb-1">{deal.title}</h4>
                  <p className="text-[10px] text-slate-500 line-clamp-2 whitespace-normal leading-tight">{deal.description}</p>
                </div>
                <div className="mt-3 flex items-center justify-between">
                  <span className="text-[9px] font-black text-blue-600 bg-blue-50 px-2 py-0.5 rounded-full">BEST PRICE</span>
                  <svg className="w-4 h-4 text-slate-300 group-hover:text-blue-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3"/></svg>
                </div>
              </a>
            ))
          )}
        </div>
      </div>

      {/* Main Shop Interface */}
      <div className="flex-1 overflow-hidden flex flex-col">
        <ChatInterface mode={AppMode.MAPS} />
      </div>
    </div>
  );
};

